  // DUT signals
  reg         clk;
  reg         reset_n;
  reg         cs;
  reg         we;
  reg  [7:0]  address;
  reg  [31:0] write_data;
  wire [31:0] read_data;

  // Instantiate DUT
  aes dut (
    .clk        (clk),
    .reset_n    (reset_n),
    .cs         (cs),
    .we         (we),
    .address    (address),
    .write_data (write_data),
    .read_data  (read_data)
  );

  // Clock generation: 10ns period
  initial clk = 0;
  always #5 clk = ~clk;

  // Write task
  task write_word;
    input [7:0]  addr;
    input [31:0] data;
    begin
      @(posedge clk);
      #1;
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      #20;
      cs         = 0;
      we         = 0;
    end
  endtask

  // Read task
  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      @(posedge clk);
      #1;
      cs      = 1;
      we      = 0;
      address = addr;
      #20;
      data = read_data;
      cs   = 0;
    end
  endtask

  // Variables
  reg [31:0] rd0, rd1, rd2, rd3;
  reg [127:0] result;
  reg [127:0] expected;

  initial begin
    // Initialize
    cs         = 0;
    we         = 0;
    address    = 0;
    write_data = 0;
    reset_n    = 0;
    repeat(4) @(posedge clk);
